            aCross = (RotL64(aWorkLaneB[((S_BLOCK1 - aIndex + 28242U)) & S_BLOCK1], 51U) ^ RotL64(aEarthLaneB[((S_BLOCK1 - aIndex + 28852U)) & S_BLOCK1], 18U));
