            //
            aOrbiterE = ((aWandererE + RotL64(aIngress, 57U)) + 0xED91DAC2ABDEA8B4ULL) + aPhaseCOrbiterAssignSaltB[((aIndex + 7U)) & S_SALT1];
            aOrbiterF = (aWandererH + RotL64(aCross, 14U)) + 0x861167D737E5AB36ULL;
            aOrbiterI = (aWandererA + RotL64(aScatter, 21U)) + 0x736C0F7DCA0C311AULL;
            aOrbiterD = (((aWandererF + RotL64(aPrevious, 43U)) + RotL64(aCarry, 39U)) + 0xFAEAD540C633319EULL) + aPhaseCOrbiterAssignSaltF[((aIndex + 26U)) & S_SALT1];
            aOrbiterG = (aWandererC + RotL64(aIngress, 5U)) + 0x8B0D8BCEBE34A31FULL;
            aOrbiterC = (aWandererG + RotL64(aPrevious, 27U)) + 0x8DA9224F2A9873BBULL;
            aOrbiterK = ((aWandererJ + RotL64(aScatter, 51U)) + RotL64(aCarry, 19U)) + 0x91EA67D69789EB4AULL;
            aOrbiterB = ((aWandererD + RotL64(aCross, 10U)) + RotL64(aCarry, 57U)) + 0x0A2AE2DC71BCFC72ULL;
            aOrbiterA = (aWandererB + RotL64(aIngress, 39U)) + 0x9BC290F0F2370602ULL;
            //
            aOrbiterE = (aOrbiterE + aOrbiterF) + 0xEEB8F7DCDF058A6AULL;
