            aOrbiterC = ((aOrbiterC + aOrbiterI) + 0xCFA2C1D9C6642537ULL) + aPhaseCOrbiterUpdateSaltF[(((31U - aIndex) + 14U)) & S_SALT1];
            aOrbiterD = (aOrbiterD ^ aOrbiterC) ^ 0xA36679A0E733AF76ULL;
