            //
            aOrbiterI = (aOrbiterI + aOrbiterK) + 0xA4F30281A1C68B10ULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterI) ^ 0xAC28DC3832AE09E6ULL;
            aOrbiterG = RotL64((aOrbiterG * 0x2E7057A91F5CC72DULL), 47U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterB) + 0x3207AB4D038E5477ULL;
            aOrbiterF = ((aOrbiterF ^ aOrbiterG) ^ 0x52A3BBF04C452A56ULL) ^ aPhaseCOrbiterUpdateSaltB[((aIndex + 10U)) & S_SALT1];
            aOrbiterF = RotL64((aOrbiterF * 0x464A9C79B2A94797ULL), 19U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterC) + 0xC848319B6E229E33ULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterK) ^ 0x11A9CCC8CB6135CBULL;
            aOrbiterB = RotL64((aOrbiterB * 0x916B75320E5AA179ULL), 5U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterD) + 0x6EA4FD6BBD3523E2ULL;
            aOrbiterA = (aOrbiterA ^ aOrbiterB) ^ 0x20B8A2DA3E31B511ULL;
            aOrbiterA = RotL64((aOrbiterA * 0x736D6174165764DFULL), 57U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterA) + 0xCA03A9901DDE81F9ULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterF) ^ 0x7087918858A61460ULL;
