            //
            aOrbiterA = ((aOrbiterA + aOrbiterE) + 0x57DBA5C6EFEBD3E3ULL) + aPhaseCOrbiterUpdateSaltE[((aIndex + 9U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterA) ^ 0xCFCBF68C9D46BE1FULL;
            aOrbiterC = RotL64((aOrbiterC * 0x5BA3435E6FABA4B1ULL), 51U);
            //
            aIngress = aOrbiterK ^ RotL64(aOrbiterA, 21U);
            aIngress = aIngress + (aOrbiterC ^ RotL64(aOrbiterB, 58U));
            aIngress = aIngress + (RotL64(aOrbiterF, 5U) ^ aOrbiterD);
            aIngress = aIngress + (aOrbiterI ^ RotL64(aOrbiterG, 43U));
