            aOrbiterJ = (aOrbiterJ + aOrbiterD) + 0x73D01868E2118704ULL;
            aOrbiterK = ((aOrbiterK ^ aOrbiterJ) ^ 0x50EB72F3878BB769ULL) ^ aPhaseGOrbiterUpdateSaltA[(((31U - aIndex) + 21U)) & S_SALT1];
            aOrbiterK = RotL64((aOrbiterK * 0x6B4263BF209E773FULL), 43U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterK) + 0x503459C703CDBF1BULL;
