            aOrbiterB = RotL64((aOrbiterB * 0x4D4EF825D41C5A27ULL), 57U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterB) + 0x9BAC948E6E84CCBCULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterE) ^ 0x14CF3B2880A60B2CULL;
