            aOrbiterG = RotL64((aOrbiterG * 0x1A3E5A3458DBA5B5ULL), 19U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterJ) + 0x80CCB5608CA2E54AULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterH) ^ 0x598161D6F52BB6FEULL;
            aOrbiterC = RotL64((aOrbiterC * 0x556B2F3BB03BD88FULL), 3U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterH) + 0xF6F80C96EC10E419ULL;
            aOrbiterD = ((aOrbiterD ^ aOrbiterB) ^ 0x4F4650DDB545ECD6ULL) ^ aPhaseGOrbiterUpdateSaltC[((aIndex + 7U)) & S_SALT1];
            aOrbiterD = RotL64((aOrbiterD * 0x775895753F31D3CDULL), 51U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterE) + 0xF26E7D1EBC2CB2F8ULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterI) ^ 0xD0340C84152F8A7CULL;
            aOrbiterH = RotL64((aOrbiterH * 0x91CE73CA6CD95A9FULL), 35U);
            //
