            aWandererA = aWandererA ^ ((RotL64(aScatter, 21U) + RotL64(aOrbiterE, 27U)) + aOrbiterA);
            aWandererH = aWandererH + (((RotL64(aPrevious, 46U) + RotL64(aOrbiterK, 53U)) + aOrbiterE) + RotL64(aCarry, 13U));
            aWandererG = aWandererG ^ (((RotL64(aScatter, 29U) + aOrbiterA) + RotL64(aOrbiterJ, 21U)) + aPhaseGWandererUpdateSaltE[(((31U - aIndex) + 9U)) & S_SALT1]);
