            //
            aOrbiterE = (aWandererH + RotL64(aIngress, 51U)) + 0x6DC299FB101A1CE5ULL;
            aOrbiterF = (aWandererB + RotL64(aPrevious, 4U)) + 0x47672AB2624AE26DULL;
            aOrbiterA = (aWandererA + RotL64(aCross, 43U)) + 0xDDDE633B3F34344BULL;
            aOrbiterG = ((aWandererK + RotL64(aScatter, 47U)) + 0x71AFCEAA87DC1B36ULL) + aPhaseHOrbiterAssignSaltC[((aIndex + 3U)) & S_SALT1];
            aOrbiterI = (aWandererG + RotL64(aCross, 39U)) + 0xE1947721ACCEE3C9ULL;
            aOrbiterC = ((aWandererE + RotL64(aIngress, 19U)) + RotL64(aCarry, 39U)) + 0xD4A85C4A6E8B8717ULL;
            aOrbiterJ = ((aWandererC + RotL64(aScatter, 11U)) + RotL64(aCarry, 21U)) + 0xA31E92423C28A254ULL;
            aOrbiterK = (((aWandererJ + RotL64(aPrevious, 58U)) + RotL64(aCarry, 13U)) + 0xC51FDA8507C11A07ULL) + aPhaseHOrbiterAssignSaltB[(((31U - aIndex) + 8U)) & S_SALT1];
