            //
            aOrbiterE = ((aOrbiterE + aOrbiterF) + 0xE5CE2FB7DE19D6E5ULL) + aPhaseHOrbiterUpdateSaltF[(((31U - aIndex) + 14U)) & S_SALT1];
            aOrbiterA = (aOrbiterA ^ aOrbiterE) ^ 0xE5E578D0CEA1ED8DULL;
            aOrbiterA = RotL64((aOrbiterA * 0xF9C9E672AE2ACE0DULL), 29U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterE) + 0x99FB407DD29D8EEEULL;
            aOrbiterI = (aOrbiterI ^ aOrbiterG) ^ 0x2391775344ADE5AFULL;
            aOrbiterI = RotL64((aOrbiterI * 0xB5A676976E7711BFULL), 47U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterA) + 0x47715F2EB4BEB03AULL;
            aOrbiterC = ((aOrbiterC ^ aOrbiterI) ^ 0x73F836A6E7B57514ULL) ^ aPhaseHOrbiterUpdateSaltD[((aIndex + 11U)) & S_SALT1];
            aOrbiterC = RotL64((aOrbiterC * 0xE7BA4BD2E7608FB5ULL), 37U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterJ) + 0x6A21AB54A0FCDE11ULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterA) ^ 0x6955509E93EC305EULL;
            aOrbiterK = RotL64((aOrbiterK * 0xE9FCED88B8359F05ULL), 5U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterI) + 0x1F9EE07C28D11AE1ULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterJ) ^ 0xEC4C24F951AAEF89ULL;
            aOrbiterH = RotL64((aOrbiterH * 0xA77573C49F4B6E6BULL), 19U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterH) + 0xCF7D857F71309626ULL;
            aOrbiterG = ((aOrbiterG ^ aOrbiterK) ^ 0xC93161AE0557F7E7ULL) ^ aPhaseHOrbiterUpdateSaltB[((aIndex + 16U)) & S_SALT1];
            aOrbiterG = RotL64((aOrbiterG * 0xB821637D89A596C7ULL), 43U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterK) + 0x0D03B08F6DA11ACEULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterC) ^ 0x8671C8C710B49445ULL;
            aOrbiterF = RotL64((aOrbiterF * 0x05C5CEB25EA65503ULL), 13U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterC) + 0x0D890932E7A5014CULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterH) ^ 0xC3362DC2BDC6B29BULL;
