            //
            aOrbiterF = (aOrbiterF + aOrbiterG) + 0xD54D78F870362E96ULL;
            aOrbiterJ = ((aOrbiterJ ^ aOrbiterF) ^ 0x79BDCAA173837C6EULL) ^ aPhaseHOrbiterUpdateSaltA[(((31U - aIndex) + 17U)) & S_SALT1];
